// Function to calculate the shortest distance using Dijkstra's algorithm
int dijkstra(vector<vector<int>> &graph, int N, int start) {
    vector<int> dist(N, INF);
    dist[start] = 0;
    priority_queue<pii, vector<pii>, greater<pii>> pq;
    pq.push({0, start});
    while (!pq.empty()) {
        int u = pq.top().second;
        pq.pop();
        for (int v = 0; v < N; v++)
            if (graph[u][v] != INF && dist[v] > dist[u] + graph[u][v]) {
                dist[v] = dist[u] + graph[u][v];
                pq.push({dist[v], v});
            }
    }
    return *min_element(dist.begin(), dist.end());
}

