import java.util.Scanner;
import java.util.PriorityQueue;
import java.util.Arrays;
public class Main {
    static final int INF = Integer.MAX_VALUE;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[][] graph = new int[N][N];
            for (int i = 0; i < N; i++)
                Arrays.fill(graph[i], INF);
            // Read edges and construct the graph
            for (int i = 0; i < N - 1; i++) {
                int v = sc.nextInt() - 1;
                int u = sc.nextInt() - 1;
                int l = sc.nextInt();
                graph[v][u] = l;
                graph[u][v] = l;
            }
            // Read previously met squares
            int[] A = new int[M];
            for (int i = 0; i < M; i++)
                A[i] = sc.nextInt() - 1;
            // Calculate expected distance
            long sum = 0;
            for (int i = 0; i < M; i++)
                for (int j = i + 1; j < M; j++) {
                    int dist = dijkstra(graph, N, A[i]);
                    sum += dist;
                }
            System.out.println(sum + " " + M * (M - 1));
        }
    }
    static int dijkstra(int[][] graph, int N, int start) {
        int[] dist = new int[N];
        Arrays.fill(dist, INF);
        dist[start] = 0;
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[1] - b[1]);
        pq.offer(new int[] {start, 0});
        while (!pq.isEmpty()) {
            int[] arr = pq.poll();
            int u = arr[0];
            for (int v = 0; v < N; v++)
                if (graph[u][v] != INF && dist[v] > dist[u] + graph[u][v]) {
                    dist[v] = dist[u] + graph[u][v];
                    pq.offer(new int[] {v, dist[v]});
                }
        }
        return Arrays.stream(dist).min().getAsInt();
    }
}

